INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41237a9a-e783-4b00-96f5-d87ac34a53d1', $q$Schema markup generator$q$, $q$Automatically generates structured data markup reflecting business information.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41237a9a-e783-4b00-96f5-d87ac34a53d1', $q$Profile protection$q$, $q$Monitors for and alerts on unauthorized changes to a Google Business Profile.$q$, 7);
