INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41237a9a-e783-4b00-96f5-d87ac34a53d1', $q$Simplified 2026 pricing structure reduced plan complexity for agencies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41237a9a-e783-4b00-96f5-d87ac34a53d1', $q$Starting price ($39-49/month) is higher than some single-purpose rank trackers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41237a9a-e783-4b00-96f5-d87ac34a53d1', $q$Pro tier jumps significantly in price ($149-169/month) for agencies needing multiple profiles$q$, 1);
